import React, { useState, useEffect } from 'react';
import { 
  Users, CreditCard, Settings, Bell, Home, User, Lock, Mail, LogOut, 
  Smartphone, Zap, ShieldCheck, CheckCircle2, ArrowLeft, ChevronRight, 
  Globe, CreditCard as CardIcon, Eye, Download, X, Upload, Trash2, Save,
  ShieldAlert, Landmark, Building, Menu, FileText, Calendar, Clock, Check
} from 'lucide-react';

const App = () => {
  const [userRole, setUserRole] = useState(null); 
  const [loginMode, setLoginMode] = useState('tenant'); 
  const [activeTab, setActiveTab] = useState('Dashboard');
  const [showPaymentSystem, setShowPaymentSystem] = useState(false);
  
  // --- Global Logic Settings ---
  const [globalSettings] = useState({
    lateFeePerDay: 50,
    gracePeriod: 5
  });

  // --- Combined Data Engine ---
  const [tenants, setTenants] = useState([
    { 
      id: 1, 
      name: 'Rajesh Kumar', 
      room: 'A-101', 
      status: 'No Request', 
      rentAmount: 12500,
      dueDate: '2026-04-01', 
      phone: '+91 98765 43210',
      email: 'rajesh.k@example.com',
      electricity: { old: 1050, current: 1150, pricePerUnit: 8, units: 100, total: 800 },
      lastPayment: null 
    },
    { 
      id: 2, 
      name: 'Anita Sharma', 
      room: 'B-204', 
      status: 'No Request', 
      rentAmount: 15000,
      dueDate: '2026-04-05', 
      phone: '+91 88776 65544',
      email: 'anita.s@example.com',
      electricity: { old: 900, current: 1000, pricePerUnit: 8, units: 100, total: 800 },
      lastPayment: null 
    }
  ]);

  const calculateLateFee = (dueDate) => {
    const today = new Date();
    const due = new Date(dueDate);
    const diffTime = today - due;
    const diffDays = Math.floor(diffTime / (1000 * 60 * 60 * 24));
    const lateDays = diffDays - globalSettings.gracePeriod;
    return lateDays > 0 ? { days: lateDays, amount: lateDays * globalSettings.lateFeePerDay } : { days: 0, amount: 0 };
  };

  const handlePaymentComplete = (tenantId) => {
    setTenants(prev => prev.map(t => t.id === tenantId ? { ...t, status: 'Pending Approval' } : t));
    setShowPaymentSystem(false);
  };

  const processDecision = (tenantId, decision) => {
    const status = decision === 'Approve' ? 'Approved' : 'Rejected';
    const currentTenant = tenants.find(t => t.id === tenantId);
    const feeInfo = calculateLateFee(currentTenant.dueDate);
    
    setTenants(prev => prev.map(t => t.id === tenantId ? { 
      ...t, 
      status: status,
      lastPayment: status === 'Approved' ? {
        date: new Date().toLocaleString(),
        total: t.rentAmount + t.electricity.total + feeInfo.amount,
        lateFee: feeInfo.amount,
        lateDays: feeInfo.days
      } : null
    } : t));
  };

  if (!userRole) {
    return (
      <div className="min-h-screen bg-[#0F172A] flex items-center justify-center p-6">
        <div className="w-full max-w-4xl bg-white rounded-[3rem] overflow-hidden shadow-2xl grid grid-cols-1 md:grid-cols-2">
          <div className="bg-slate-900 p-16 text-white flex flex-col justify-between hidden md:flex">
            <div className="flex items-center gap-3 italic font-black text-2xl">
              <div className="w-10 h-10 bg-indigo-600 rounded-2xl flex items-center justify-center not-italic text-sm">H</div> Homely
            </div>
            <h1 className="text-5xl font-black leading-tight italic">Managed.<br/>Simplified.<br/>Live.</h1>
            <p className="text-slate-500 font-bold uppercase tracking-widest text-[10px]">Unified Portal v5.2</p>
          </div>
          <div className="p-12 flex flex-col justify-center">
            <div className="flex gap-2 p-1 bg-slate-100 rounded-2xl mb-10">
              <button onClick={() => setLoginMode('tenant')} className={`flex-1 py-4 rounded-xl text-[10px] font-black uppercase transition-all ${loginMode === 'tenant' ? 'bg-white text-indigo-600 shadow-xl' : 'text-slate-400'}`}>Resident</button>
              <button onClick={() => setLoginMode('admin')} className={`flex-1 py-4 rounded-xl text-[10px] font-black uppercase transition-all ${loginMode === 'admin' ? 'bg-white text-indigo-600 shadow-xl' : 'text-slate-400'}`}>Landlord</button>
            </div>
            <button onClick={() => {setUserRole(loginMode); setActiveTab(loginMode === 'admin' ? 'Dashboard' : 'Overview');}} className="w-full bg-slate-900 text-white font-black py-5 rounded-2xl uppercase tracking-[0.2em] text-xs shadow-2xl hover:bg-indigo-600 transition-all">Login</button>
          </div>
        </div>
      </div>
    );
  }

  return userRole === 'admin' ? (
    <AdminPortal tenants={tenants} onDecision={processDecision} logout={() => setUserRole(null)} activeTab={activeTab} setActiveTab={setActiveTab} />
  ) : (
    <TenantPortal 
      tenant={tenants[0]} 
      lateFeeCalc={calculateLateFee} 
      onShowPayment={() => setShowPaymentSystem(true)} 
      showPaymentSystem={showPaymentSystem}
      setShowPaymentSystem={setShowPaymentSystem}
      onPayComplete={() => handlePaymentComplete(tenants[0].id)}
      logout={() => setUserRole(null)} 
    />
  );
};

// --- ADMIN PORTAL ---
const AdminPortal = ({ tenants, onDecision, logout, activeTab, setActiveTab }) => {
  return (
    <div className="flex h-screen bg-[#F8FAFC]">
      <aside className="w-72 bg-slate-900 text-white p-8 flex flex-col hidden md:flex">
        <div className="flex items-center gap-3 font-black italic text-xl mb-12">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center not-italic">H</div> Homely
        </div>
        <nav className="space-y-2 flex-1">
          {['Dashboard', 'Approvals', 'Tenants', 'Settings'].map(tab => (
            <button key={tab} onClick={() => setActiveTab(tab)} className={`w-full flex items-center gap-4 px-6 py-4 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === tab ? 'bg-indigo-600 text-white shadow-xl' : 'text-slate-500 hover:text-white'}`}>
              {tab === 'Dashboard' && <Home size={18}/>}
              {tab === 'Approvals' && <ShieldCheck size={18}/>}
              {tab === 'Tenants' && <Users size={18}/>}
              {tab === 'Settings' && <Settings size={18}/>}
              {tab}
            </button>
          ))}
          <button onClick={logout} className="w-full flex items-center gap-4 px-6 py-4 text-red-400 text-[10px] font-black uppercase mt-auto"><LogOut size={18}/> Logout</button>
        </nav>
      </aside>

      <main className="flex-1 overflow-y-auto p-12">
        <h2 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.3em] mb-8">{activeTab}</h2>
        
        {activeTab === 'Approvals' && (
            <div className="space-y-6">
                {tenants.filter(t => t.status === 'Pending Approval').map(t => (
                    <div key={t.id} className="bg-white p-10 rounded-[3rem] border flex items-center justify-between shadow-sm animate-in fade-in zoom-in-95">
                        <div>
                            <p className="font-black text-xl italic">{t.name} <span className="text-slate-300 not-italic ml-2">{t.room}</span></p>
                            <p className="text-[10px] font-bold text-indigo-600 uppercase tracking-widest mt-1">Rent + Utilities Submitted</p>
                        </div>
                        <div className="flex gap-4">
                            <button onClick={() => onDecision(t.id, 'Approve')} className="p-5 bg-emerald-500 text-white rounded-2xl hover:scale-110 transition-transform"><Check/></button>
                            <button onClick={() => onDecision(t.id, 'Reject')} className="p-5 bg-red-500 text-white rounded-2xl hover:scale-110 transition-transform"><X/></button>
                        </div>
                    </div>
                ))}
                {tenants.filter(t => t.status === 'Pending Approval').length === 0 && <p className="text-slate-400 font-bold italic">No pending transactions.</p>}
            </div>
        )}
        {activeTab === 'Dashboard' && <p className="font-black italic text-2xl">Welcome Back, Admin.</p>}
      </main>
    </div>
  );
};

// --- TENANT PORTAL WITH INTEGRATED PAYMENT SYSTEM ---
const TenantPortal = ({ tenant, lateFeeCalc, onShowPayment, showPaymentSystem, setShowPaymentSystem, onPayComplete, logout }) => {
  const [activeTab, setActiveTab] = useState('Overview');
  const feeInfo = lateFeeCalc(tenant.dueDate);
  const totalPayable = tenant.rentAmount + tenant.electricity.total + feeInfo.amount;

  return (
    <div className="min-h-screen bg-[#FDFDFD] flex flex-col relative">
      <header className="h-24 bg-white border-b px-12 flex items-center justify-between sticky top-0 z-40">
         <div className="flex items-center gap-3 italic font-black text-xl text-indigo-600">
             <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white not-italic text-sm">H</div> MyHome
         </div>
         <nav className="flex gap-10">
            {['Overview', 'Bills', 'Settings'].map(t => (
               <button key={t} onClick={() => setActiveTab(t)} className={`text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === t ? 'text-indigo-600 border-b-2 border-indigo-600' : 'text-slate-300'}`}>{t}</button>
            ))}
         </nav>
         <button onClick={logout} className="p-3 bg-white border rounded-xl text-red-500"><LogOut size={18}/></button>
      </header>

      <main className="p-12 max-w-5xl mx-auto w-full">
        <div className="bg-slate-900 rounded-[3.5rem] p-16 text-white shadow-2xl relative overflow-hidden mb-12">
            <div className="absolute top-0 right-0 p-10">
                <span className={`text-[9px] font-black uppercase px-4 py-2 rounded-full ${feeInfo.amount > 0 ? 'bg-red-500' : 'bg-emerald-500'}`}>
                    {feeInfo.amount > 0 ? `Late Fee Active` : 'On Time'}
                </span>
            </div>
            <p className="text-[10px] font-black uppercase text-indigo-300 mb-4 tracking-widest italic">Room {tenant.room}</p>
            <h2 className="text-7xl font-black italic mb-12">₹{totalPayable.toLocaleString()}</h2>
            
            {tenant.status === 'No Request' || tenant.status === 'Rejected' ? (
                <button onClick={onShowPayment} className="bg-indigo-600 px-12 py-5 rounded-2xl font-black uppercase text-xs shadow-xl hover:bg-indigo-500 transition-all">Request Approval</button>
            ) : (
                <div className={`px-12 py-5 rounded-2xl font-black uppercase text-xs flex items-center gap-3 w-fit ${tenant.status === 'Approved' ? 'bg-emerald-500 text-white' : 'bg-orange-500/20 text-orange-400'}`}>
                    {tenant.status === 'Approved' ? <CheckCircle2 size={18}/> : <Clock size={18}/>} {tenant.status}
                </div>
            )}
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div className="bg-white p-12 rounded-[3rem] border shadow-sm">
                <h4 className="text-[10px] font-black text-slate-400 uppercase italic mb-8">Breakdown</h4>
                <div className="space-y-4 text-xs font-bold">
                    <div className="flex justify-between"><span>Base Rent</span> <span>₹{tenant.rentAmount}</span></div>
                    <div className="flex justify-between"><span>Electricity ({tenant.electricity.units} units)</span> <span>₹{tenant.electricity.total}</span></div>
                    {feeInfo.amount > 0 && <div className="flex justify-between text-red-500"><span>Late Fee</span> <span>+ ₹{feeInfo.amount}</span></div>}
                    <div className="pt-4 border-t flex justify-between text-lg font-black italic"><span>Total Payable</span> <span>₹{totalPayable}</span></div>
                </div>
            </div>

            {tenant.status === 'Approved' && (
                <div className="bg-white p-12 rounded-[3rem] border-4 border-dashed border-slate-100 flex flex-col justify-center items-center text-center animate-in zoom-in-95">
                    <ShieldCheck className="text-emerald-500 mb-4" size={48}/>
                    <h3 className="text-xl font-black italic uppercase mb-2">Verified Receipt</h3>
                    <p className="text-[10px] font-bold text-slate-400 uppercase mb-8">Paid on {tenant.lastPayment.date}</p>
                    <button className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black uppercase text-[10px] flex items-center justify-center gap-2"><Download size={16}/> Get PDF</button>
                </div>
            )}
        </div>
      </main>

      {/* --- INTEGRATED PAYMENT MODAL SYSTEM --- */}
      {showPaymentSystem && (
        <div className="fixed inset-0 bg-slate-900/90 backdrop-blur-xl z-[60] flex items-center justify-center p-6">
           <div className="bg-white w-full max-w-5xl rounded-[4rem] overflow-hidden shadow-2xl grid grid-cols-1 md:grid-cols-5 animate-in zoom-in-95 duration-300">
              <div className="md:col-span-2 bg-indigo-600 p-16 text-white flex flex-col justify-between relative">
                 <button onClick={() => setShowPaymentSystem(false)} className="absolute top-8 left-8 p-3 hover:bg-white/10 rounded-full transition-all"><ArrowLeft size={24}/></button>
                 <div className="mt-12">
                    <p className="text-[10px] font-black uppercase tracking-[0.3em] opacity-60 mb-4">Total Amount Due</p>
                    <h2 className="text-6xl font-black italic tracking-tighter">₹{totalPayable.toLocaleString()}</h2>
                 </div>
                 <div className="space-y-6">
                    <div className="flex items-center gap-4 bg-white/10 p-6 rounded-3xl backdrop-blur-md">
                       <Zap className="text-yellow-400" size={28}/>
                       <div>
                          <p className="text-[8px] font-black uppercase opacity-60">Instant Verification</p>
                          <p className="text-xs font-bold italic">Approval sent to landlord</p>
                       </div>
                    </div>
                    <p className="text-[9px] font-bold opacity-40 uppercase tracking-widest">Secure Gateway Protected</p>
                 </div>
              </div>
              
              <div className="md:col-span-3 p-16 flex flex-col justify-center space-y-8">
                 <h3 className="text-2xl font-black italic uppercase text-slate-900">Choose Method</h3>
                 <div className="grid grid-cols-2 gap-4">
                    <button className="p-6 border-2 border-indigo-600 rounded-3xl bg-indigo-50 flex flex-col items-center gap-4 group transition-all">
                       <Smartphone className="text-indigo-600 group-hover:scale-110 transition-transform" size={32}/>
                       <span className="text-[10px] font-black uppercase tracking-widest text-indigo-600">UPI Payment</span>
                    </button>
                    <button className="p-6 border-2 border-slate-100 rounded-3xl flex flex-col items-center gap-4 text-slate-300 cursor-not-allowed">
                       <CardIcon size={32}/>
                       <span className="text-[10px] font-black uppercase tracking-widest">Debit Card</span>
                    </button>
                 </div>
                 <button 
                   onClick={onPayComplete}
                   className="w-full bg-slate-900 text-white py-6 rounded-3xl font-black uppercase text-[11px] tracking-[0.4em] shadow-2xl hover:bg-indigo-600 transition-all active:scale-95"
                 >
                   Verify & Notify Landlord
                 </button>
                 <p className="text-center text-[9px] font-black text-slate-300 uppercase flex items-center justify-center gap-2"><Lock size={14}/> Encrypted Session</p>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default App;
